module pulse_detect(
    input clk,
    input rst_n,
    input data_in,
    output data_out
);

reg [1:0] state;
reg data_out_reg;

localparam IDLE = 2'b00;
localparam PULSE = 2'b01;
localparam WAIT = 2'b10;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        data_out_reg <= 1'b0;
    end else begin
        case (state)
            IDLE: begin
                if (data_in) begin
                    state <= PULSE;
                end else begin
                    state <= IDLE;
                end
            end
            PULSE: begin
                if (data_in) begin
                    state <= WAIT;
                end else begin
                    state <= IDLE;
                end
            end
            WAIT: begin
                if (data_in) begin
                    state <= WAIT;
                end else begin
                    state <= IDLE;
                end
            end
            default: begin
                state <= IDLE;
            end
        endcase
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out_reg <= 1'b0;
    end else begin
        if (state == PULSE) begin
            data_out_reg <= 1'b1;
        end else begin
            data_out_reg <= 1'b0;
        end
    end
end

assign data_out = data_out_reg;

endmodule
